    21  export function lookupHomeForUserWith(
    22    username: string,
    23    platform: NodeJS.Platform,
    24    execFileFn: typeof execFileSync,
    25    readFileFn: typeof readFileSync
   26  ): string {
   27    // Method 1: getent passwd (Linux/POSIX — handles LDAP, NIS, local via NSS)
   28    if (platform !== "darwin") {
   29      try {
   29        const out = execFileFn("getent", ["passwd", username], {
   30          encoding: "utf8",
   31          stdio: ["ignore", "pipe", "ignore"],
   32        }).trim();
   33        const home = (out as string).split(":")[5];
   34        if (typeof home === "string" && home.startsWith("/")) return home;
   35      } catch {
   36        // getent unavailable or user not found — try next method
   37      }
   38    }
