   40    // Method 2: dscl (macOS directory services)
   41    if (platform === "darwin") {
   42      try {
   43        const out = execFileFn(
   44          "dscl",
   45          [".", "-read", `/Users/${username}`, "NFSHomeDirectory"],
   46          { encoding: "utf8", stdio: ["ignore", "pipe", "ignore"] }
   47        ).trim();
   48        const home = (out as string).replace(/^NFSHomeDirectory:\s*/, "").trim();
   49        if (home.startsWith("/")) return home;
   50      } catch {
   51        // dscl unavailable or user record not found — try next method
   52      }
   53    }
